mapper.select:
SELECT * FROM diem_dung_chan WHERE ma_tuyen = #{maTuyen} AND thu_tu = #{thuTu}
AND ma != #{maLoaiTru}
LIMIT 1

SELECT * FROM diem_dung_chan WHERE ma_tuyen = #{maTuyen} AND LOWER(TRIM(ten_diem)) = LOWER(TRIM(#{tenDiem}))
AND ma != #{maLoaiTru}
LIMIT 1

mapper.update:
UPDATE diem_dung_chan SET ma_tuyen = #{maTuyen}, ten_diem = #{tenDiem},
    thu_tu = #{thuTu}, thoi_gian_dung_phut = #{thoiGianDungPhut},
    vi_do = #{viDo}, kinh_do = #{kinhDo}
WHERE ma = #{ma}
